/**
 * CSV Parser Library for TypeScript
 * Provides robust CSV parsing with type coercion, error handling, and aggregation methods
 */

/**
 * Options for CSV parsing
 */
export interface CSVOptions {
  delimiter?: string;      // Field delimiter (default: ',')
  quote?: string;          // Quote character (default: '"')
  lineSeparator?: string;  // Line separator (default: '\n' or '\r\n')
}

/**
 * Represents a parsing error
 */
export interface ParseError {
  row: number;
  message: string;
}

/**
 * Result of CSV parsing with data and methods
 */
export interface CSVResultData {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: ParseError[];
}

/**
 * Main CSV result class with query methods
 */
export class CSVResult implements CSVResultData {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: ParseError[];

  constructor(data: CSVResultData) {
    this.rows = data.rows;
    this.headers = data.headers;
    this.errors = data.errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
    return new CSVResult({
      rows: this.rows.filter(predicate),
      headers: this.headers,
      errors: this.errors,
    });
  }

  /**
   * Sum numeric values in a column
   */
  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number') {
        return acc + value;
      }
      return acc;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    const numericValues = this.rows
      .map((row) => row[column])
      .filter((value): value is number => typeof value === 'number');

    if (numericValues.length === 0) {
      return 0;
    }

    return numericValues.reduce((acc, val) => acc + val, 0) / numericValues.length;
  }

  /**
   * Count total number of rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column: string): Map<unknown, Array<Record<string, unknown>>> {
    const groups = new Map<unknown, Array<Record<string, unknown>>>();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }

    return groups;
  }
}

/**
 * Detects and coerces value types
 */
function coerceType(value: string): unknown {
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  if (value.toLowerCase() === 'true') {
    return true;
  }

  if (value.toLowerCase() === 'false') {
    return false;
  }

  const numberValue = Number(value);
  if (!isNaN(numberValue) && value.trim() !== '') {
    return numberValue;
  }

  return value;
}

/**
 * Detects the line separator in the input
 */
function detectLineSeparator(input: string): string {
  if (input.includes('\r\n')) {
    return '\r\n';
  }
  if (input.includes('\n')) {
    return '\n';
  }
  return '\n';
}

/**
 * Parses a CSV string into structured data
 */
export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? detectLineSeparator(input);

  const rows: Array<Record<string, unknown>> = [];
  const errors: ParseError[] = [];

  if (!input || input.trim() === '') {
    return new CSVResult({
      rows: [],
      headers: [],
      errors: [],
    });
  }

  // Split into lines
  const lines = input.split(lineSeparator);

  if (lines.length === 0) {
    return new CSVResult({
      rows: [],
      headers: [],
      errors: [],
    });
  }

  // Parse headers from first line
  let headers: string[] = [];
  try {
    headers = parseCSVLine(lines[0], delimiter, quote);
  } catch (error) {
    return new CSVResult({
      rows: [],
      headers: [],
      errors: [
        {
          row: 1,
          message: `Failed to parse header row: ${error instanceof Error ? error.message : 'Unknown error'}`,
        },
      ],
    });
  }

  // Parse data rows
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (!line || line.trim() === '') {
      continue;
    }

    try {
      const fields = parseCSVLine(line, delimiter, quote);

      // Handle rows with mismatched column count
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Expected ${headers.length} columns but got ${fields.length}`,
        });
        continue;
      }

      const row: Record<string, unknown> = {};
      for (let j = 0; j < headers.length; j++) {
        row[headers[j]] = coerceType(fields[j]);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: i + 1,
        message: `Failed to parse row: ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
    }
  }

  return new CSVResult({
    rows,
    headers,
    errors,
  });
}

/**
 * Parses a single CSV line into fields
 * Handles quoted fields and escaped quotes
 */
function parseCSVLine(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = i + 1 < line.length ? line[i + 1] : '';

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote: two quotes in a row = one literal quote
        current += quote;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // End of field
      fields.push(current);
      current = '';
      i++;
    } else {
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  return fields;
}

/**
 * Comprehensive test suite for CSV Parser
 */

import { parseCSV, CSVResult } from './csv-parser';

/**
 * Simple assertion function
 */
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

/**
 * Deep equality check for objects and arrays
 */
function deepEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a === null || b === null) return a === b;
  if (typeof a !== typeof b) return false;

  if (typeof a === 'object' && typeof b === 'object') {
    if (Array.isArray(a) && Array.isArray(b)) {
      if (a.length !== b.length) return false;
      return a.every((item, index) => deepEqual(item, b[index]));
    }

    const keysA = Object.keys(a as Record<string, unknown>).sort();
    const keysB = Object.keys(b as Record<string, unknown>).sort();
    if (keysA.length !== keysB.length) return false;
    if (!keysA.every((key, index) => key === keysB[index])) return false;

    return keysA.every((key) =>
      deepEqual((a as Record<string, unknown>)[key], (b as Record<string, unknown>)[key]),
    );
  }

  return false;
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  if (!deepEqual(actual, expected)) {
    console.error('Expected:', expected);
    console.error('Actual:', actual);
    throw new Error(`Assertion failed: ${message}`);
  }
}

/**
 * Test runner
 */
let testCount = 0;
let passedTests = 0;
let failedTests = 0;

function test(name: string, fn: () => void): void {
  testCount++;
  try {
    fn();
    passedTests++;
    console.log(`✓ ${name}`);
  } catch (error) {
    failedTests++;
    console.error(`✗ ${name}`);
    console.error(`  ${error instanceof Error ? error.message : String(error)}\n`);
  }
}

/**
 * Test Suite: Basic Parsing
 */
test('Basic parsing - simple CSV', () => {
  const csv = `name,age,city\nAlice,30,NYC\nBob,25,LA`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEqual(
    result.rows[0],
    { name: 'Alice', age: 30, city: 'NYC' },
    'First row should be parsed correctly',
  );
  assertEqual(result.errors.length, 0, 'Should have no errors');
});

test('Basic parsing - single column', () => {
  const csv = `product\nApple\nBanana`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.headers, ['product'], 'Header should be product');
  assertEqual(result.rows[0], { product: 'Apple' }, 'First row should match');
});

test('Basic parsing - single row', () => {
  const csv = `name,value\nTest,123`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, 'Should have 1 row');
  assertEqual(result.rows[0], { name: 'Test', value: 123 }, 'Row should match');
});

test('Basic parsing - empty input', () => {
  const result = parseCSV('');

  assertEqual(result.rows.length, 0, 'Should have no rows');
  assertEqual(result.headers.length, 0, 'Should have no headers');
  assertEqual(result.errors.length, 0, 'Should have no errors');
});

test('Basic parsing - whitespace only', () => {
  const result = parseCSV('   \n   \n  ');

  assertEqual(result.rows.length, 0, 'Should have no rows');
});

/**
 * Test Suite: Quoted Fields
 */
test('Quoted fields - comma inside quotes', () => {
  const csv = `name,description\n"Doe, John","A person from New York"`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, 'Doe, John', 'Name should handle comma in quotes');
  assertEqual(
    result.rows[0].description,
    'A person from New York',
    'Description should parse correctly',
  );
});

test('Quoted fields - multiple quoted fields', () => {
  const csv = `name,address,city\n"Smith, Bob","123 Main St, Apt 4","Boston, MA"`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, 'Smith, Bob', 'Quoted name with comma');
  assertEqual(result.rows[0].address, '123 Main St, Apt 4', 'Quoted address with comma');
  assertEqual(result.rows[0].city, 'Boston, MA', 'Quoted city with comma');
});

test('Quoted fields - mixed quoted and unquoted', () => {
  const csv = `id,name,score\n1,"John Doe",95.5\n2,Jane,87.0`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, 'John Doe', 'First row quoted name');
  assertEqual(result.rows[1].name, 'Jane', 'Second row unquoted name');
  assertEqual(result.rows[0].score, 95.5, 'First row score');
});

test('Quoted fields - newline in quoted field', () => {
  const csv = `id,comment\n1,"This is a\nmultiline\ncomment"`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].comment, 'This is a\nmultiline\ncomment', 'Should preserve newlines in quoted field');
});

/**
 * Test Suite: Escaped Quotes
 */
test('Escaped quotes - double quote inside quoted field', () => {
  const csv = `name,quote\n"John ""The King"" Doe","He said ""Hello"""`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, 'John "The King" Doe', 'Should handle escaped quotes in name');
  assertEqual(result.rows[0].quote, 'He said "Hello"', 'Should handle escaped quotes in quote field');
});

test('Escaped quotes - multiple consecutive quotes', () => {
  const csv = `text\n"""quoted"""`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].text, '"quoted"', 'Should handle multiple quotes');
});

test('Escaped quotes - single quote edge case', () => {
  const csv = `value\n""""`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].value, '"', 'Should parse single escaped quote');
});

/**
 * Test Suite: Custom Delimiters
 */
test('Custom delimiter - semicolon', () => {
  const csv = `name;age;city\nAlice;30;NYC\nBob;25;LA`;
  const result = parseCSV(csv, { delimiter: ';' });

  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should be split by semicolon');
  assertEqual(result.rows[0].name, 'Alice', 'Data should be split by semicolon');
});

test('Custom delimiter - tab', () => {
  const csv = `name\tage\tcity\nAlice\t30\tNYC`;
  const result = parseCSV(csv, { delimiter: '\t' });

  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should be split by tab');
  assertEqual(result.rows[0].age, 30, 'Data should be split by tab');
});

test('Custom delimiter - pipe with quoted fields', () => {
  const csv = `name|description\n"Smith|John"|"Works at Tech|Corp"`;
  const result = parseCSV(csv, { delimiter: '|' });

  assertEqual(result.rows[0].name, 'Smith|John', 'Should handle pipe in quoted field');
  assertEqual(result.rows[0].description, 'Works at Tech|Corp', 'Should handle multiple pipes');
});

test('Custom quote character - single quote', () => {
  const csv = `name,value\n'Smith, John',123`;
  const result = parseCSV(csv, { quote: "'" });

  assertEqual(result.rows[0].name, 'Smith, John', 'Should respect custom quote character');
});

/**
 * Test Suite: Type Coercion
 */
test('Type coercion - integers', () => {
  const csv = `id,count\n1,100\n2,200`;
  const result = parseCSV(csv);

  assert(typeof result.rows[0].id === 'number', 'ID should be number');
  assert(typeof result.rows[0].count === 'number', 'Count should be number');
  assertEqual(result.rows[0].id, 1, 'ID should be 1');
  assertEqual(result.rows[0].count, 100, 'Count should be 100');
});

test('Type coercion - floats', () => {
  const csv = `price,rating\n19.99,4.5\n29.99,3.75`;
  const result = parseCSV(csv);

  assert(typeof result.rows[0].price === 'number', 'Price should be number');
  assertEqual(result.rows[0].price, 19.99, 'Price should be 19.99');
  assertEqual(result.rows[0].rating, 4.5, 'Rating should be 4.5');
});

test('Type coercion - booleans true', () => {
  const csv = `active,enabled\ntrue,TRUE\nfalse,False`;
  const result = parseCSV(csv);

  assert(result.rows[0].active === true, 'lowercase true should be boolean true');
  assert(result.rows[0].enabled === true, 'uppercase TRUE should be boolean true');
  assert(result.rows[1].active === false, 'lowercase false should be boolean false');
  assert(result.rows[1].enabled === false, 'Mixed case False should be boolean false');
});

test('Type coercion - null values', () => {
  const csv = `id,name,value\n1,,null\n2,NULL,\n3,data,null`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, null, 'Empty string should be null');
  assertEqual(result.rows[0].value, null, 'null should be null');
  assertEqual(result.rows[1].name, null, 'NULL should be null');
  assertEqual(result.rows[1].value, null, 'Empty string should be null');
  assertEqual(result.rows[2].name, 'data', 'Non-empty should be string');
});

test('Type coercion - strings', () => {
  const csv = `id,name,email\n1,John,john@example.com\n2,Jane,jane@example.com`;
  const result = parseCSV(csv);

  assert(typeof result.rows[0].name === 'string', 'Name should be string');
  assert(typeof result.rows[0].email === 'string', 'Email should be string');
  assertEqual(result.rows[0].name, 'John', 'Name should be John');
});

test('Type coercion - negative numbers', () => {
  const csv = `value\n-42\n-3.14`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].value, -42, 'Negative integer should be coerced');
  assertEqual(result.rows[1].value, -3.14, 'Negative float should be coerced');
});

test('Type coercion - numbers as strings', () => {
  const csv = `text\n"123"\n"45.67"`;
  const result = parseCSV(csv);

  assert(typeof result.rows[0].text === 'string', 'Quoted number should remain string');
  assertEqual(result.rows[0].text, '123', 'Quoted number should be "123"');
});

test('Type coercion - scientific notation', () => {
  const csv = `value\n1e5\n2.5e-3`;
  const result = parseCSV(csv);

  assertEqual(result.rows[0].value, 1e5, 'Scientific notation should be coerced');
  assertEqual(result.rows[1].value, 2.5e-3, 'Scientific notation with negative exponent');
});

/**
 * Test Suite: Error Handling
 */
test('Error handling - mismatched column count', () => {
  const csv = `name,age,city\nAlice,30,NYC\nBob,25`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, 'Should have 1 valid row');
  assertEqual(result.errors.length, 1, 'Should have 1 error');
  assertEqual(result.errors[0].row, 3, 'Error should be on row 3');
  assert(result.errors[0].message.includes('Expected 3 columns'), 'Error message should mention column mismatch');
});

test('Error handling - empty rows are skipped', () => {
  const csv = `name,age\nAlice,30\n\nBob,25\n\n`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows (empty rows skipped)');
  assertEqual(result.errors.length, 0, 'Should have no errors');
});

test('Error handling - multiple errors collected', () => {
  const csv = `name,age\nAlice,30\nBob\nCharlie,25,extra\nDave,22`;
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 valid rows');
  assertEqual(result.errors.length, 2, 'Should have 2 errors');
  assert(result.errors.some((e) => e.row === 3), 'Should have error on row 3');
  assert(result.errors.some((e) => e.row === 4), 'Should have error on row 4');
});

/**
 * Test Suite: Filter Functionality
 */
test('Filter - basic filter', () => {
  const csv = `name,age\nAlice,30\nBob,25\nCharlie,35`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => (row.age as number) > 25);
  assertEqual(filtered.rows.length, 2, 'Should have 2 rows after filter');
  assertEqual(filtered.rows[0].name, 'Alice', 'Should include Alice');
  assertEqual(filtered.rows[1].name, 'Charlie', 'Should include Charlie');
});

test('Filter - string matching', () => {
  const csv = `name,department\nAlice,Sales\nBob,IT\nCharlie,Sales`;
  const result = parseCSV(csv);

  const salesOnly = result.filter((row) => row.department === 'Sales');
  assertEqual(salesOnly.rows.length, 2, 'Should have 2 Sales rows');
  assert(salesOnly.rows.every((r) => r.department === 'Sales'), 'All should be Sales');
});

test('Filter - chained filters', () => {
  const csv = `name,age,salary\nAlice,30,60000\nBob,25,50000\nCharlie,35,70000`;
  const result = parseCSV(csv);

  const filtered = result
    .filter((row) => (row.age as number) >= 30)
    .filter((row) => (row.salary as number) > 60000);

  assertEqual(filtered.rows.length, 1, 'Should have 1 row after chained filters');
  assertEqual(filtered.rows[0].name, 'Charlie', 'Should be Charlie');
});

test('Filter - no matches', () => {
  const csv = `name,age\nAlice,30\nBob,25`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => (row.age as number) > 100);
  assertEqual(filtered.rows.length, 0, 'Should have 0 rows');
});

/**
 * Test Suite: Aggregation - Sum
 */
test('Sum - basic sum', () => {
  const csv = `id,amount\n1,100\n2,200\n3,150`;
  const result = parseCSV(csv);

  const total = result.sum('amount');
  assertEqual(total, 450, 'Sum should be 450');
});

test('Sum - with null values', () => {
  const csv = `id,amount\n1,100\n2,\n3,150`;
  const result = parseCSV(csv);

  const total = result.sum('amount');
  assertEqual(total, 250, 'Sum should skip null values');
});

test('Sum - mixed types', () => {
  const csv = `id,value\n1,100\n2,text\n3,200`;
  const result = parseCSV(csv);

  const total = result.sum('value');
  assertEqual(total, 300, 'Sum should skip non-numeric values');
});

test('Sum - empty result set', () => {
  const csv = `id,amount\n1,100\n2,200`;
  const result = parseCSV(csv);

  const filtered = result.filter((r) => (r.id as number) > 10);
  assertEqual(filtered.sum('amount'), 0, 'Sum of empty set should be 0');
});

/**
 * Test Suite: Aggregation - Average
 */
test('Average - basic average', () => {
  const csv = `id,score\n1,80\n2,90\n3,100`;
  const result = parseCSV(csv);

  const avg = result.average('score');
  assertEqual(avg, 90, 'Average should be 90');
});

test('Average - with decimals', () => {
  const csv = `id,value\n1,10.5\n2,20.3\n3,30.2`;
  const result = parseCSV(csv);

  const avg = result.average('value');
  assert(Math.abs(avg - 20.333333333) < 0.01, 'Average should be approximately 20.33');
});

test('Average - with null values', () => {
  const csv = `id,score\n1,100\n2,\n3,100`;
  const result = parseCSV(csv);

  const avg = result.average('score');
  assertEqual(avg, 100, 'Average should exclude null values');
});

test('Average - no numeric values', () => {
  const csv = `id,text\n1,hello\n2,world`;
  const result = parseCSV(csv);

  const avg = result.average('text');
  assertEqual(avg, 0, 'Average with no numbers should be 0');
});

test('Average - empty result set', () => {
  const csv = `id,score\n1,80`;
  const result = parseCSV(csv);

  const filtered = result.filter((r) => (r.id as number) > 10);
  assertEqual(filtered.average('score'), 0, 'Average of empty set should be 0');
});

/**
 * Test Suite: Aggregation - Count
 */
test('Count - basic count', () => {
  const csv = `id,name\n1,Alice\n2,Bob\n3,Charlie`;
  const result = parseCSV(csv);

  assertEqual(result.count(), 3, 'Count should be 3');
});

test('Count - after filter', () => {
  const csv = `id,status\n1,active\n2,inactive\n3,active`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.status === 'active');
  assertEqual(filtered.count(), 2, 'Count after filter should be 2');
});

test('Count - empty result', () => {
  const result = parseCSV('');
  assertEqual(result.count(), 0, 'Empty result count should be 0');
});

/**
 * Test Suite: Aggregation - GroupBy
 */
test('GroupBy - basic grouping', () => {
  const csv = `id,category,value\n1,A,10\n2,B,20\n3,A,15\n4,B,25`;
  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assertEqual(grouped.size, 2, 'Should have 2 groups');
  assert(grouped.has('A'), 'Should have group A');
  assert(grouped.has('B'), 'Should have group B');
  assertEqual(grouped.get('A')!.length, 2, 'Group A should have 2 rows');
  assertEqual(grouped.get('B')!.length, 2, 'Group B should have 2 rows');
});

test('GroupBy - string grouping', () => {
  const csv = `id,department\n1,Sales\n2,IT\n3,Sales\n4,HR`;
  const result = parseCSV(csv);

  const grouped = result.groupBy('department');
  assertEqual(grouped.size, 3, 'Should have 3 departments');
  assertEqual(grouped.get('Sales')!.length, 2, 'Sales should have 2 people');
  assertEqual(grouped.get('IT')!.length, 1, 'IT should have 1 person');
});

test('GroupBy - numeric grouping', () => {
  const csv = `id,level\n1,1\n2,2\n3,1\n4,3\n5,2`;
  const result = parseCSV(csv);

  const grouped = result.groupBy('level');
  assertEqual(grouped.size, 3, 'Should have 3 levels');
  assertEqual(grouped.get(1)!.length, 2, 'Level 1 should have 2 rows');
  assertEqual(grouped.get(2)!.length, 2, 'Level 2 should have 2 rows');
  assertEqual(grouped.get(3)!.length, 1, 'Level 3 should have 1 row');
});

test('GroupBy - with null values', () => {
  const csv = `id,category\n1,A\n2,\n3,A\n4,`;
  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assert(grouped.has('A'), 'Should have group A');
  assert(grouped.has(null), 'Should have null group');
  assertEqual(grouped.get('A')!.length, 2, 'Group A should have 2 rows');
  assertEqual(grouped.get(null)!.length, 2, 'Null group should have 2 rows');
});

test('GroupBy - single group', () => {
  const csv = `id,status\n1,active\n2,active\n3,active`;
