/**
 * CSV Parser Library for TypeScript
 * Provides robust CSV parsing with type coercion, error handling, and aggregation methods
 */

/**
 * Options for CSV parsing
 */
export interface CSVOptions {
  delimiter?: string;      // Field delimiter (default: ',')
  quote?: string;          // Quote character (default: '"')
  lineSeparator?: string;  // Line separator (default: '\n' or '\r\n')
}

/**
 * Represents a parsing error
 */
export interface ParseError {
  row: number;
  message: string;
}

/**
 * Result of CSV parsing with data and methods
 */
export interface CSVResultData {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: ParseError[];
}

/**
 * Main CSV result class with query methods
 */
export class CSVResult implements CSVResultData {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: ParseError[];

  constructor(data: CSVResultData) {
    this.rows = data.rows;
    this.headers = data.headers;
    this.errors = data.errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
    return new CSVResult({
      rows: this.rows.filter(predicate),
      headers: this.headers,
      errors: this.errors,
    });
  }

  /**
   * Sum numeric values in a column
   */
  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number') {
        return acc + value;
      }
      return acc;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    const numericValues = this.rows
      .map((row) => row[column])
      .filter((value): value is number => typeof value === 'number');

    if (numericValues.length === 0) {
      return 0;
    }

    return numericValues.reduce((acc, val) => acc + val, 0) / numericValues.length;
  }

  /**
   * Count total number of rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column: string): Map<unknown, Array<Record<string, unknown>>> {
    const groups = new Map<unknown, Array<Record<string, unknown>>>();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }

    return groups;
  }
}

/**
 * Detects and coerces value types
 */
function coerceType(value: string): unknown {
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  if (value.toLowerCase() === 'true') {
    return true;
  }

  if (value.toLowerCase() === 'false') {
    return false;
  }

  const numberValue = Number(value);
  if (!isNaN(numberValue) && value.trim() !== '') {
    return numberValue;
  }

  return value;
}

/**
 * Detects the line separator in the input
 */
function detectLineSeparator(input: string): string {
  if (input.includes('\r\n')) {
    return '\r\n';
  }
  if (input.includes('\n')) {
    return '\n';
  }
  return '\n';
}

/**
 * Parses a CSV string into structured data
 */
export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? detectLineSeparator(input);

  const rows: Array<Record<string, unknown>> = [];
  const errors: ParseError[] = [];

  if (!input || input.trim() === '') {
    return new CSVResult({
      rows: [],
      headers: [],
      errors: [],
    });
  }

  // Split into lines
  const lines = input.split(lineSeparator);

  if (lines.length === 0) {
    return new CSVResult({
      rows: [],
      headers: [],
      errors: [],
    });
  }

  // Parse headers from first line
  let headers: string[] = [];
  try {
    headers = parseCSVLine(lines[0], delimiter, quote);
  } catch (error) {
    return new CSVResult({
      rows: [],
      headers: [],
      errors: [
        {
          row: 1,
          message: `Failed to parse header row: ${error instanceof Error ? error.message : 'Unknown error'}`,
        },
      ],
    });
  }

  // Parse data rows
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (!line || line.trim() === '') {
      continue;
    }

    try {
      const fields = parseCSVLine(line, delimiter, quote);

      // Handle rows with mismatched column count
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Expected ${headers.length} columns but got ${fields.length}`,
        });
        continue;
      }

      const row: Record<string, unknown> = {};
      for (let j = 0; j < headers.length; j++) {
        row[headers[j]] = coerceType(fields[j]);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: i + 1,
        message: `Failed to parse row: ${error instanceof Error ? error.message : 'Unknown error'}`,
      });
    }
  }

  return new CSVResult({
    rows,
    headers,
    errors,
  });
}

/**
 * Parses a single CSV line into fields
 * Handles quoted fields and escaped quotes
 */
function parseCSVLine(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = i + 1 < line.length ? line[i + 1] : '';

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote: two quotes in a row = one literal quote
        current += quote;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // End of field
      fields.push(current);
      current = '';
      i++;
    } else {
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  return fields;
}

